"},"$:/plugins/rimir/theme/styles":{"title":"$:/plugins/rimir/theme/styles","created":"20260305110732198","modified":"20260305110732198","tags":"$:/tags/Stylesheet","type":"text/vnd.tiddlywiki","text":"/* ============================================================
   rimir Theme — Shared Visual Classes
   Prefix: rr-
   ============================================================ */

/* --- Tabs --- */
.rr-tabs {
	display: flex;
	border-bottom: 1px solid <<colour tiddler-border>>;
	background: <<colour page-background>>;
	border-radius: 4px 4px 0 0;
}

.rr-tab {
	padding: 6px 16px;
	border: none;
	background: none;
	cursor: pointer;
	color: <<colour muted-foreground>>;
	border-bottom: 2px solid transparent;
	font-size: 0.9em;
	font-family: inherit;
	line-height: inherit;
}

.rr-tab:hover {
	color: <<colour foreground>>;
	background: <<colour tiddler-background>>;
}

.rr-tab-active {
	color: <<colour foreground>>;
	border-bottom-color: <<colour primary>>;
	font-weight: bold;
}

/* --- Panels --- */
.rr-panel {
	border: 1px solid <<colour tiddler-border>>;
	border-radius: 4px;
	background: <<colour tiddler-background>>;
}

.rr-panel-body {
	padding: 8px 12px;
}

/* --- Tables --- */
.rr-table {
	width: 100%;
	border-collapse: collapse;
	font-size: 0.9em;
}

.rr-table th,
.rr-table td {
	border: 1px solid <<colour table-border>>;
	padding: 4px 8px;
	text-align: left;
}

.rr-table th {
	background: <<colour table-header-background>>;
	color: <<colour muted-foreground>>;
	font-weight: normal;
}

.rr-table tr:hover td {
	filter: brightness(0.95);
}

.rr-row-error td {
	background: #fdd;
}

.rr-row-warn td {
	background: #fed;
}

.rr-row-error td:first-child,
.rr-row-warn td:first-child {
	white-space: nowrap;
}

/* --- Callout boxes --- */
.rr-callout {
	padding: 12px 16px;
	border-radius: 4px;
	margin: 1em 0;
	border-left: 4px solid;
	font-size: 0.92em;
}

.rr-callout-label {
	font-weight: 700;
	text-transform: uppercase;
	font-size: 0.8em;
	letter-spacing: 0.5px;
	margin-bottom: 4px;
}

.rr-callout-info {
	border-left-color: #3b82f6;
	background: rgba(59, 130, 246, 0.08);
}
.rr-callout-info .rr-callout-label { color: #3b82f6; }

.rr-callout-warning {
	border-left-color: #d97706;
	background: rgba(217, 119, 6, 0.08);
}
.rr-callout-warning .rr-callout-label { color: #d97706; }

.rr-callout-tip {
	border-left-color: #16a34a;
	background: rgba(22, 163, 74, 0.08);
}
.rr-callout-tip .rr-callout-label { color: #16a34a; }

.rr-callout-danger {
	border-left-color: #dc2626;
	background: rgba(220, 38, 38, 0.08);
}
.rr-callout-danger .rr-callout-label { color: #dc2626; }

/* --- Notices (full-width banners) --- */
.rr-notice {
	margin-top: 12px;
	padding: 12px;
	border-radius: 4px;
	font-weight: bold;
}

.rr-notice-warning {
	background: #fff3cd;
	border: 1px solid #ffc107;
}

.rr-notice-info {
	background: #d1ecf1;
	border: 1px solid #bee5eb;
}

.rr-notice-danger {
	background: #f8d7da;
	border: 1px solid #f5c6cb;
}

.rr-notice-success {
	background: #d4edda;
	border: 1px solid #c3e6cb;
}

/* --- Status messages --- */
.rr-status-loading {
	color: <<colour muted-foreground>>;
	font-style: italic;
	padding: 8px 0;
}

.rr-status-error {
	color: <<colour alert-highlight>>;
	padding: 8px;
	background: <<colour alert-background>>;
	border: 1px solid <<colour alert-border>>;
	border-radius: 3px;
	font-size: 0.9em;
}

.rr-status-success {
	color: <<colour foreground>>;
	padding: 8px;
	background: #d4edda;
	border: 1px solid #c3e6cb;
	border-radius: 3px;
	font-size: 0.9em;
}

.rr-status-info {
	color: <<colour muted-foreground>>;
	padding: 8px 0;
}

/* --- Badges --- */
.rr-badge-circle {
	display: inline-block;
	width: 16px;
	height: 16px;
	line-height: 16px;
	text-align: center;
	border-radius: 50%;
	font-size: 12px;
	font-weight: bold;
	margin-right: 4px;
	vertical-align: middle;
}

.rr-badge-added {
	background: #28a745;
	color: white;
}

.rr-badge-removed {
	background: #dc3545;
	color: white;
}

.rr-badge-rect {
	display: inline-block;
	font-size: 0.75em;
	font-weight: 600;
	padding: 2px 8px;
	border-radius: 4px;
	text-transform: uppercase;
	letter-spacing: 0.5px;
}

/* --- Forms --- */
.rr-input-row {
	display: flex;
	gap: 8px;
	margin-bottom: 8px;
}

.rr-input {
	flex: 1;
	padding: 4px 8px;
	border: 1px solid <<colour code-border>>;
	border-radius: 3px;
	font-size: 0.9em;
	background: <<colour code-background>>;
}

/* --- Link buttons --- */
.rr-link-btn {
	color: <<colour primary>>;
	font-size: 0.85em;
	margin-right: 8px;
}

.rr-link-btn:hover {
	text-decoration: underline;
}

.rr-link-btn-danger {
	color: <<colour alert-highlight>>;
	margin-right: 0;
}

/* --- Utilities --- */
.rr-muted {
	color: <<colour muted-foreground>>;
}

.rr-mono {
	font-family: monospace;
}

.rr-nowrap {
	white-space: nowrap;
}

.rr-small {
	font-size: 0.85em;
}

/* --- Settings Hub (ControlPanel vertical tabs) --- */
.rr-settings-hub {
	display: flex;
	gap: 0;
	min-height: 400px;
	border: 1px solid <<colour tiddler-border>>;
	border-radius: 6px;
	overflow: hidden;
	background: <<colour tiddler-background>>;
}

.rr-settings-sidebar {
	width: 220px;
	min-width: 220px;
	background: <<colour page-background>>;
	border-right: 1px solid <<colour tiddler-border>>;
	padding: 8px 0;
	overflow-y: auto;
}

.rr-settings-plugin-item {
	display: flex;
	align-items: center;
	gap: 8px;
	width: 100%;
	padding: 8px 14px;
	border: none;
	background: none;
	cursor: pointer;
	text-align: left;
	font-family: inherit;
	font-size: 0.9em;
	color: <<colour foreground>>;
	border-left: 3px solid transparent;
	transition: background 0.15s;
}

.rr-settings-plugin-item:hover {
	background: <<colour tiddler-background>>;
}

.rr-settings-plugin-active {
	background: <<colour tiddler-background>>;
	border-left-color: <<colour primary>>;
	font-weight: 600;
}

.rr-settings-plugin-name {
	flex: 1;
	overflow: hidden;
	text-overflow: ellipsis;
	white-space: nowrap;
}

.rr-settings-plugin-version {
	font-size: 0.8em;
	white-space: nowrap;
}

.rr-settings-content {
	flex: 1;
	padding: 20px 24px;
	overflow-y: auto;
}

.rr-settings-header {
	display: flex;
	align-items: center;
	gap: 12px;
	margin-bottom: 20px;
	padding-bottom: 12px;
	border-bottom: 1px solid <<colour tiddler-border>>;
}

.rr-settings-header-name {
	font-size: 1.2em;
	font-weight: 600;
}

.rr-settings-header-desc {
	font-size: 0.9em;
	margin-top: 2px;
}

.rr-settings-info-card {
	padding: 16px;
	border: 1px dashed <<colour tiddler-border>>;
	border-radius: 6px;
	text-align: center;
	color: <<colour muted-foreground>>;
}
